#!/usr/bin/env node
// Pre-bundles LLM SDKs into a single browser-compatible ESM file.
// Output: src/vs/workbench/contrib/void/browser/llmMessage/llmSdkBundle.js
// This file is included in the VS Code web build via the common source tree,
// but its contents are a self-contained bundle (not re-processed by esbuild).

import esbuild from 'esbuild';
import { readFileSync, writeFileSync, mkdirSync } from 'fs';
import { fileURLToPath } from 'url';
import path from 'path';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.join(__dirname, '..');
const OUT_FILE = path.join(REPO_ROOT, 'src/vs/workbench/contrib/void/browser/llmMessage/llmSdkBundle.js');

mkdirSync(path.dirname(OUT_FILE), { recursive: true });

// Entry: re-export everything we need from each SDK
const entryCode = `
export { default as Anthropic } from '@anthropic-ai/sdk';
export { default as OpenAI, AzureOpenAI } from 'openai';
export { Ollama } from 'ollama/browser';
export { MistralCore } from '@mistralai/mistralai/core.js';
export { fimComplete } from '@mistralai/mistralai/funcs/fimComplete.js';
export { GoogleGenAI, Type } from '@google/genai';
`;

const result = await esbuild.build({
	stdin: { contents: entryCode, resolveDir: REPO_ROOT, loader: 'js' },
	bundle: true,
	format: 'iife',
	globalName: '__NI_LLM_SDKS',
	platform: 'browser',
	conditions: ['browser', 'import', 'default'],
	target: ['es2022'],
	// Stub Node-only packages
	plugins: [{
		name: 'stub-node-only',
		setup(build) {
				// Stub Node-only or polyfill packages
			build.onResolve({ filter: /^(google-auth-library|whatwg-fetch)$/ }, (args) => ({
				path: args.path, namespace: 'stub'
			}));
			build.onResolve({ filter: /^@aws-sdk\// }, (args) => ({
				path: args.path, namespace: 'stub'
			}));
			build.onLoad({ filter: /.*/, namespace: 'stub' }, () => ({
				contents: `export default {}; export const GoogleAuth = class {}; export const BedrockRuntimeClient = class {}; export const ConverseStreamCommand = class {}; export const defaultProvider = () => ({});`,
				loader: 'js',
			}));
		}
	}],
	write: false,
	metafile: false,
});

if (result.errors.length > 0) {
	console.error('LLM bundle errors:', result.errors);
	process.exit(1);
}

const banner = `// AUTO-GENERATED by scripts/build-llm-bundle.mjs — do not edit by hand\n`;
writeFileSync(OUT_FILE, banner + result.outputFiles[0].text);
console.log('LLM SDK bundle written to', OUT_FILE, `(${Math.round(result.outputFiles[0].text.length / 1024)}KB)`);
